PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?winner ?winnerLabel
WHERE {
  ?event wdt:P31 wd:Q3372482;
         rdfs:label ?eventLabel;
         wdt:P585 ?date;
         wdt:P1444 ?winner.
  FILTER (CONTAINS(LCASE(?eventLabel), "ncaa women's championship") && 
          YEAR(?date) = 2017)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?winner ?winnerLabel
WHERE {
  ?event wdt:P31 wd:Q919133;  
         rdfs:label ?eventLabel;
         wdt:P585 ?date;
         wdt:P1444 ?winner.
  FILTER (CONTAINS(LCASE(?eventLabel), 'women\'s basketball') &&
          YEAR(?date) = 2017)
  FILTER (LANG(?eventLabel) = 'en')
  ?winner rdfs:label ?winnerLabel.
  FILTER (LANG(?winnerLabel) = 'en')
}

